var backround = createSprite(200, 200);
backround.setAnimation("background");
var football = createSprite(60, 200);
football.setAnimation("football");
football.scale = 0.15;
football.visible = false;
var play = createSprite(200, 200);
play.setAnimation("play");
var pillar1 = createSprite(330, 338);
pillar1.setAnimation("pillar1");
pillar1.scale = 0.55;
pillar1.visible = false;
var pillar2 = createSprite(330, 62);
pillar2.setAnimation("pillar2");
pillar2.scale = 0.55;
pillar2.rotation = 180;
pillar2.visible = false;
var plane = createSprite(485, 100);
plane.setAnimation("plane");
plane.visible = false;
plane.scale = 0.9;
var score = 0;
var scored1 = false;
var scored2 = false;
var gameOver = false;
var gameState = "start";
function draw() {
  background("gray");
  plane.velocityY = 1;
  if (gameState === "start") {
    showStartScreen();
    return;
  }
  if (gameOver) {
    showGameOver();
    return;
  }
  runGame();
}
function showStartScreen() {
  play.visible = true;
  backround.visible = false;
  fill("white");
  textSize(20);
  text("Press Space or Click Play to Start", 48, 270);
  drawSprites();
  if (mousePressedOver(play) || keyWentDown("space")) {
    startGame();
  }
}
function startGame() {
  gameState = "play";
  play.visible = false;
  backround.visible = true;
  football.visible = true;
  pillar1.visible = true;
  pillar2.visible = true;
  plane.visible = true;
  football.y = 200;
  football.velocityY = 5;
  pillar1.x = 330;
  pillar2.x = 330;
  plane.x = 475;
  plane.y = randomNumber(50, 250);
  plane.velocityX = -3.5;
  score = 0;
  scored1 = false;
  scored2 = false;
  gameOver = false;
}
function runGame() {
football.velocityY += 0.5;
if (keyWentDown("space") || mouseWentDown("leftButton")) {
football.velocityY = -8;
 }
pillar1.velocityX = -3.5;
pillar2.velocityX = -3.5;
if (score > 1) {
  pillar1.velocityX = -15;
  pillar2.velocityX = -15;
  plane.velocityX = -15;
}
if (score < 11) {
  pillar1.velocityX = -3.5;
  pillar2.velocityX = -3.5;
  plane.velocityX = -3.5;
}
if (pillar1.x < 20) {
   pillar1.x = 300;
   scored1 = false;
 }
if (pillar2.x < 20) {
   pillar2.x = 300;
   scored2 = false;
 }
if (plane.x < -10) {
   plane.x = 275;
   plane.y = randomNumber(50, 250);
 }
if (pillar1.x < football.x && !scored1) {
score += 0.5;
scored1 = true;
 }
if (pillar2.x < football.x && !scored2) {
score += 0.5;
scored2 = true;
 }
if (football.y > 405) {
gameOver = true;
}
if (football.y < -5) {
gameOver = true;
}
if (football.isTouching(pillar1)) {
gameOver = true;
}
if (football.isTouching(pillar2)) {
  gameOver = true;
}
if (football.isTouching(plane)) {
gameOver = true;
}
drawSprites();
fill("black");
textSize(20);
textAlign(RIGHT, TOP);
text("Score: " + score, 390, 10);
}
function showGameOver() {
  background("black");
  fill("red");
  textSize(50);
  textAlign(CENTER);
  text("GAME OVER!", 200, 180);
  textSize(30);
  text("Score: " + score, 200, 240);
}
